import{_ as e,o as a,c as r,a7 as d}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Ultra (超维)","description":"","frontmatter":{},"headers":[],"relativePath":"en/realms/ultra.md","filePath":"en/realms/ultra.md","lastUpdated":1775394001000}'),n={name:"en/realms/ultra.md"};function i(l,t,s,o,c,h){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="ultra-超维" tabindex="-1">Ultra (超维) <a class="header-anchor" href="#ultra-超维" aria-label="Permalink to &quot;Ultra (超维)&quot;">​</a></h1><p><span class="realm-badge realm-ultra">Ultra</span> is the realm of higher dimensions. Ultra Awakeners specialize in gaining <strong>extra turns</strong> by playing multiple cards, creating snowball chains that overwhelm enemies.</p><h2 id="core-identity" tabindex="-1">Core Identity <a class="header-anchor" href="#core-identity" aria-label="Permalink to &quot;Core Identity&quot;">​</a></h2><p>Ultra is a speed-focused realm that rewards playing as many cards as possible per turn. When conditions are met, Ultra effects grant additional actions or full extra turns, allowing you to take far more actions than your opponent. Currently ranked as an <strong>A-tier realm</strong> -- a veteran strong team with a high ceiling but surpassed by Aequor and Caro.</p><h2 id="key-mechanics" tabindex="-1">Key Mechanics <a class="header-anchor" href="#key-mechanics" aria-label="Permalink to &quot;Key Mechanics&quot;">​</a></h2><h3 id="realm-talent-hyperdimension-space" tabindex="-1">Realm Talent: Hyperdimension Space <a class="header-anchor" href="#realm-talent-hyperdimension-space" aria-label="Permalink to &quot;Realm Talent: Hyperdimension Space&quot;">​</a></h3><p>After activating the Ultra realm talent, a &quot;Hyperdimension Space&quot; appears above the team. Each turn, copies of the first command cards played are stored in this space. When the storage reaches its limit, the team enters an <strong>extra Ultra turn</strong> where all stored cards become hand cards.</p><h3 id="pure-ultra-resonance" tabindex="-1">Pure Ultra Resonance <a class="header-anchor" href="#pure-ultra-resonance" aria-label="Permalink to &quot;Pure Ultra Resonance&quot;">​</a></h3><p>In a pure Ultra composition, the Proficiency stat effect is <strong>doubled</strong>, and the ability reduction penalty during extra turns is <strong>completely nullified</strong>.</p><h3 id="extra-turns-from-card-play" tabindex="-1">Extra Turns from Card Play <a class="header-anchor" href="#extra-turns-from-card-play" aria-label="Permalink to &quot;Extra Turns from Card Play&quot;">​</a></h3><p>The core Ultra mechanic triggers when you play a certain number of cards in a single turn:</p><ul><li>Playing multiple cards in one turn builds toward the extra turn threshold.</li><li>Once triggered, you gain an additional turn immediately.</li><li>Extra turns can chain into further extra turns if you continue playing enough cards.</li></ul><h3 id="low-cost-card-synergy" tabindex="-1">Low-Cost Card Synergy <a class="header-anchor" href="#low-cost-card-synergy" aria-label="Permalink to &quot;Low-Cost Card Synergy&quot;">​</a></h3><p>Ultra decks prioritize low Arithmetica cost cards to maximize the number of cards played per turn:</p><table tabindex="0"><thead><tr><th>Card Cost</th><th>Role in Ultra Decks</th></tr></thead><tbody><tr><td>0-1 cost</td><td>Core cards; play multiple per turn to trigger extra turns</td></tr><tr><td>2 cost</td><td>Balanced picks; playable alongside cheap cards</td></tr><tr><td>3+ cost</td><td>Generally avoided; too expensive for chain potential</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The ideal Ultra turn plays 3-4 low-cost cards, triggers an extra turn, then plays 3-4 more. Card draw effects that keep your hand full are extremely valuable.</p></div><h2 id="ultra-awakeners" tabindex="-1">Ultra Awakeners <a class="header-anchor" href="#ultra-awakeners" aria-label="Permalink to &quot;Ultra Awakeners&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Awakener</th><th>Role</th><th>Tier</th><th>Availability</th></tr></thead><tbody><tr><td>Arachne</td><td>Attack</td><td>—</td><td>Limited (v2.5)</td></tr><tr><td>Casiah</td><td>Sub-Attack</td><td>T1</td><td>Standard</td></tr><tr><td>Castor</td><td>Defense</td><td>—</td><td>Limited</td></tr><tr><td>Clementine</td><td>Support</td><td>—</td><td>Limited</td></tr><tr><td>Daffodil</td><td>Attack</td><td>T0</td><td>Limited</td></tr><tr><td>Erica</td><td>Defense</td><td>T0</td><td>Free (Caro Rift I)</td></tr><tr><td>Horla</td><td>Support</td><td>—</td><td>Standard</td></tr><tr><td>Jenkins</td><td>Sub-Attack</td><td>T1</td><td>Standard</td></tr><tr><td>Liz</td><td>Attack</td><td>T0</td><td>Standard</td></tr><tr><td>Pollux</td><td>Attack</td><td>—</td><td>Limited</td></tr><tr><td>Tincture</td><td>Support</td><td>T2</td><td>Standard</td></tr><tr><td>Wanda</td><td>Defense</td><td>—</td><td>Standard</td></tr><tr><td>Winkle</td><td>Support</td><td>T1</td><td>Standard</td></tr></tbody></table><h2 id="team-building-with-ultra" tabindex="-1">Team Building with Ultra <a class="header-anchor" href="#team-building-with-ultra" aria-label="Permalink to &quot;Team Building with Ultra&quot;">​</a></h2><ul><li><strong>Ultra Poison Team (Beginner Recommended)</strong> -- Wanda + Nodera (1-awaken) + Erica (1-awaken) + Nymphia/Winkle: Best beginner team. Only Wanda is mandatory. Nymphia + Poison Tarot can indefinitely stall bosses. Realm Mastery 100+ recommended.</li><li><strong>Ultra Starter Team</strong> -- Liz + Erica + Ogier + Doll: All free/starter characters. Stack poison and survive. Note: Liz poison meta has been surpassed by Aequor/Caro in current version.</li><li><strong>Ultra Double-C Double-Shield</strong> -- Winkle + Erica + Liz + flex: When multi-hitting enemies, prioritize Winkle&#39;s moth fire to stack green flame, then use Erica&#39;s Overload for shields.</li><li><strong>Horla Core Team</strong> -- Liz + Horla + Erica + Ramona: Horla is the core Ultra support for progression teams.</li></ul><h2 id="strengths-and-weaknesses" tabindex="-1">Strengths and Weaknesses <a class="header-anchor" href="#strengths-and-weaknesses" aria-label="Permalink to &quot;Strengths and Weaknesses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Strengths</th><th>Weaknesses</th></tr></thead><tbody><tr><td>Highest action economy in the game</td><td>Weak when chain is disrupted</td></tr><tr><td>Snowball victories; overwhelming momentum</td><td>Requires specific low-cost card pool</td></tr><tr><td>Multiple turns means more Aliemus and Silver Key generation</td><td>Individual card damage is low</td></tr><tr><td>Good for sustained fights</td><td>Has been surpassed by Aequor/Caro in current meta</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If your chain breaks (due to running out of cards or Arithmetica), Ultra teams lose their momentum and can struggle to recover. Always maintain card draw sources.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Realms Overview</a></li><li><a href="./../cards/deckbuilding.html">Deckbuilding Guide</a></li><li><a href="./../awakeners/team-building.html">Team Building</a></li></ul>',25)])])}const p=e(n,[["render",i]]);export{m as __pageData,p as default};
